// 共通：ダークテーマ上で見やすい白背景カードにテーブル/SVGを描画
const FigCard = ({ children, title }) => (
  <div className="my-4 overflow-x-auto rounded-xl border border-slate-700 bg-white p-3 shadow-lg">
    {title ? (
      <div className="mb-2 text-center text-sm font-bold text-slate-800">{title}</div>
    ) : null}
    {children}
  </div>
);

const FigTable = ({ title, rows, minWidth = "620px" }) => (
  <FigCard title={title}>
    <table className="w-full border-collapse text-sm text-slate-800" style={{ minWidth }}>
      <tbody>
        {rows.map((row, rowIndex) => (
          <tr key={rowIndex}>
            {row.map((cell, cellIndex) => (
              <td
                key={cellIndex}
                className={
                  "border border-slate-300 px-3 py-2 align-top " +
                  (rowIndex === 0 || cell?.header ? "bg-orange-100 text-center font-bold" : "bg-white")
                }
              >
                {typeof cell === "object" ? cell.text : cell}
              </td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  </FigCard>
);

